module fsm(
    input IN,
    input CLK,
    input RST,
    output MATCH
);

reg [2:0] state;
reg [2:0] next_state;
reg match_reg;

localparam STATE_IDLE = 3'b000;
localparam STATE_1 = 3'b001;
localparam STATE_10 = 3'b010;
localparam STATE_100 = 3'b011;
localparam STATE_1001 = 3'b100;
localparam STATE_10011 = 3'b101;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        state <= STATE_IDLE;
        match_reg <= 1'b0;
    end else begin
        state <= next_state;
        match_reg <= (state == STATE_10011) ? 1'b1 : 1'b0;
    end
end

always @(*) begin
    case (state)
        STATE_IDLE: begin
            if (IN) begin
                next_state = STATE_1;
            end else begin
                next_state = STATE_IDLE;
            end
        end
        STATE_1: begin
            if (IN) begin
                next_state = STATE_1;
            end else begin
                next_state = STATE_10;
            end
        end
        STATE_10: begin
            if (IN) begin
                next_state = STATE_1;
            end else begin
                next_state = STATE_100;
            end
        end
        STATE_100: begin
            if (IN) begin
                next_state = STATE_1001;
            end else begin
                next_state = STATE_IDLE;
            end
        end
        STATE_1001: begin
            if (IN) begin
                next_state = STATE_10011;
            end else begin
                next_state = STATE_100;
            end
        end
        STATE_10011: begin
            next_state = STATE_IDLE;
        end
        default: begin
            next_state = STATE_IDLE;
        end
    endcase
end

assign MATCH = match_reg;

endmodule
